questionvariables.text:
/* V1: Resistive Load, R_L > Z0, Matched Source */
Z0_val: 50;
Rg_val: 50;
RL_val: 100;
Vg_val: 10;
ell_val: 0.5;
vp_val: 200000000.0;

/* Reflection coefficients */
Gamma_L: (RL_val - Z0_val)/(RL_val + Z0_val);
Gamma_g: (Rg_val - Z0_val)/(Rg_val + Z0_val);

/* Initial forward wave */
V1_plus: Vg_val*Z0_val/(Z0_val + Rg_val);

/* One-way travel time */
T_val: ell_val/vp_val;

/* Voltage at load at t = 3T (after 1 round trip) */
V_at_3T: float(V1_plus*(1 + Gamma_L)*(1 + Gamma_L*Gamma_g));

/* VSWR */
VSWR_val: if abs(Gamma_L) < 0.999 then float((1 + abs(Gamma_L))/(1 - abs(Gamma_L))) else 999;

/* MCQ-MA */
mcq_opts: random_permutation([[1, true, "The steady-state voltage equals V_g * R_L / (R_g + R_L)"], [2, false, "The line settles after exactly one round trip (because source is matched)"], [3, true, "Increasing R_L toward Z_0 would reduce reflections at the load"], [4, false, "VSWR = 1 means the line is perfectly matched at both ends"], [5, false, "Doubling the line length doubles the number of bounces needed"]]);
correct_mcq: {1,3};

/* Teacher answers */
ta_GL: float(Gamma_L);
ta_Gg: float(Gamma_g);
ta_V1p: float(V1_plus);
ta_T: float(T_val);
ta_V3T: V_at_3T;
ta_mcq: correct_mcq;

/* V2: Resistive Load, R_L < Z0, Mismatched Source */
Z0_val: 75;
Rg_val: 50;
RL_val: 25;
Vg_val: 12;
ell_val: 0.3;
vp_val: 200000000.0;

/* Reflection coefficients */
Gamma_L: (RL_val - Z0_val)/(RL_val + Z0_val);
Gamma_g: (Rg_val - Z0_val)/(Rg_val + Z0_val);

/* Initial forward wave */
V1_plus: Vg_val*Z0_val/(Z0_val + Rg_val);

/* One-way travel time */
T_val: ell_val/vp_val;

/* Voltage at load at t = 3T (after 1 round trip) */
V_at_3T: float(V1_plus*(1 + Gamma_L)*(1 + Gamma_L*Gamma_g));

/* VSWR */
VSWR_val: if abs(Gamma_L) < 0.999 then float((1 + abs(Gamma_L))/(1 - abs(Gamma_L))) else 999;

/* MCQ-MA */
mcq_opts: random_permutation([[1, true, "The steady-state voltage equals V_g * R_L / (R_g + R_L)"], [2, false, "Since both ends are mismatched, the voltage never settles"], [3, false, "The reflection coefficient at the source is zero"], [4, true, "Changing R_L to equal Z_0 would eliminate load reflections"], [5, false, "The one-way travel time depends on the load impedance"]]);
correct_mcq: {1,4};

/* Teacher answers */
ta_GL: float(Gamma_L);
ta_Gg: float(Gamma_g);
ta_V1p: float(V1_plus);
ta_T: float(T_val);
ta_V3T: V_at_3T;
ta_mcq: correct_mcq;

/* V3: Short-Circuit Load, Mismatched Source */
